var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心裡準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"사정을 모르는 사람들이 보기에 저와 관리자님은 완전히 반대되는 길을 걷고 있다고 생각하겠죠.","JPN":"事情を知らない者達は、僕と管理者さんは正反対の道を歩んでいるのだと思うんでしょうね。","ENG":"To those who aren't in the know, you and I seem like two people on completely different paths.","TWN":"在不知情的人眼中，我和管理者大人是水火不容的關係吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"하지만 그렇지 않다는 건, 관리자님도 잘 알고 계시지 않나요?","JPN":"ですが、そうではないということは、管理者さんもよくご存知なのではありませんか？","ENG":"But you know more than anyone else that they're wrong.","TWN":"但管理者大人應該也很清楚，事實並非如此對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"목적을 이루기 위해서는 수단을 가릴 필요가 없다는 것이 제가 관리자님께 가장 먼저 배운 것이니까요.","JPN":"目的のためなら手段を選ぶ必要がない。それが、僕が管理者であるあなたから最初に学んだことです。","ENG":"Achieve your goals by any means necessary—that's the very first thing I learned from you.","TWN":"畢竟我在管理者大人身上學到的第一件事，就是為達目的不擇手段。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"관리자님께서 이 회사에 계시는 것도 그런 이유 때문이겠죠.","JPN":"管理者さんがこの会社に身を置いているのも、そういった理由からだろうと思います。","ENG":"That's probably why you're staying with this company, too.","TWN":"您會待在這間公司的原因不也是如此？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"관리국과는 달리 더 자유롭게 활동할 수 있을 테니까요.","JPN":"管理局と違って、もっと自由な活動が行えるでしょうから。","ENG":"Here, you can enjoy more freedom than you did at the Administration.","TWN":"因為不同於管理局，在這間公司您可以更自由地發揮。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"뭐, 저와 관리자님의 목적지가 완전히 동일한 것은 아니지만 적어도 우리의 길이 갈라지기 전 까지는 제가 도움을 드릴 수 있을 것 같군요.","JPN":"まあ、僕と管理者さんの目指す先がまったく同じ場所だとは思いませんが、少なくとも、いずれ道を違えるまでなら、僕からも協力できることがあると思います。","ENG":"Well, you and I may not be heading for the same destination, but I guess I can help you until our paths split.","TWN":"雖然我和您的目標不完全一致，但在我們分道揚鑣前，我還是可以幫助您的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"쓸데없는 감정 따위에 휘둘리다가 후회를 남기는 건 저도 이제 사절이니까요.","JPN":"余計な感情に振り回されて悔いを残すようなことは、僕としても、もう二度と御免ですから。","ENG":"I don't want to let my emotions get the best of me anymore.","TWN":"我已經決定，不會再因為兒女私情而徒留遺憾。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"그런 부분에 대해서는 지금도 당신과 스승님께 감사하고 있습니다.","JPN":"そういった意味では、今でもあなたと師匠には感謝しているんです。","ENG":"About that, I'm still grateful for you and the Master.","TWN":"這一點我直到如今都還是很感謝您和師父。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"그럼 잘 부탁 드리죠.","JPN":"では、よろしくお願いします。","ENG":"Thank you for choosing me.","TWN":"那就請多指教囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"아참, 수연이에게는 비밀로 해 주세요.","JPN":"そうだ、キズナには内緒にしといてくださいね。","ENG":"Ah, and please keep this secret from Sooyeon.","TWN":"對了，這件事只有您跟我知道，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_NULL","text":{"KOREA":"저도 스승님께는 비밀로 해 드릴 테니까요.","JPN":"僕も師匠には黙っていてあげますので。","ENG":"I'll keep it secret from the Master for you.","TWN":"要對師父保密喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};